import{_ as a,o as n,c as e,a1 as p}from"./chunks/framework.D-9tmlIu.js";const h=JSON.parse('{"title":"markdown里面都有些啥","description":"","frontmatter":{},"headers":[],"relativePath":"posts/天才/懒加载.md","filePath":"posts/天才/懒加载.md"}'),t={name:"posts/天才/懒加载.md"};function o(i,s,l,r,d,c){return n(),e("div",null,[...s[0]||(s[0]=[p(`<p><strong>图片懒加载（Lazy Loading）</strong> 的核心作用用四个字概括就是：<strong>延迟加载</strong>。</p><p>简单来说，当用户打开一个网页时，浏览器默认会<strong>一次性下载</strong>页面上所有的图片，不管这些图片是在屏幕顶端，还是藏在要滚动好几屏才能看到的页面最底部。</p><p>开启了懒加载后，游戏规则就变了：<strong>只有当用户向下滚动网页，图片即将进入屏幕视口（可视区域）时，浏览器才会真正开始下载这张图片。</strong></p><p>这个功能具体能带来以下几个核心好处：</p><h3 id="_1-大幅提升-首屏-加载速度" tabindex="-1">1. 大幅提升“首屏”加载速度 <a class="header-anchor" href="#_1-大幅提升-首屏-加载速度" aria-label="Permalink to &quot;1. 大幅提升“首屏”加载速度&quot;">​</a></h3><p>如果你的 Markdown 文档很长，里面插了几十张高清截图或架构图。</p><ul><li><p><strong>不开启懒加载</strong>：用户一打开网页，浏览器要同时下载几十张图片，网络带宽被占满，导致网页卡顿、白屏，用户体验很差。</p></li><li><p><strong>开启懒加载</strong>：用户刚打开网页时，浏览器只下载最顶端能看到的 1~2 张图片，网页瞬间就刷出来了（首屏秒开）。</p></li></ul><h3 id="_2-节省用户的手机流量-非常重要" tabindex="-1">2. 节省用户的手机流量（非常重要） <a class="header-anchor" href="#_2-节省用户的手机流量-非常重要" aria-label="Permalink to &quot;2. 节省用户的手机流量（非常重要）&quot;">​</a></h3><p>如果一个用户用手机流量打开了你的 VitePress 文档，他可能只想看第一段的文字，看完就直接关掉网页了。</p><ul><li><p><strong>不开启懒加载</strong>：虽然他只看了第一页，但手机在后台已经悄悄把他后面没看过的几十张图片全部下载完了，白白浪费了用户的流量。</p></li><li><p><strong>开启懒加载</strong>：他没看过的图片，网络请求连发都不会发，帮用户省下了流量。</p></li></ul><h3 id="_3-减轻你服务器的压力-降低带宽成本" tabindex="-1">3. 减轻你服务器的压力（降低带宽成本） <a class="header-anchor" href="#_3-减轻你服务器的压力-降低带宽成本" aria-label="Permalink to &quot;3. 减轻你服务器的压力（降低带宽成本）&quot;">​</a></h3><p>所有的图片都是托管在服务器（或者 CDN）上的。每次用户访问，服务器都要传输图片数据。懒加载减少了那些“用户没看完网页就关闭”所导致的无效图片请求，能直接<strong>降低你服务器的带宽消耗和流量成本</strong>。</p><h3 id="🛠️-怎么在-vitepress-中开启" tabindex="-1">🛠️ 怎么在 VitePress 中开启？ <a class="header-anchor" href="#🛠️-怎么在-vitepress-中开启" aria-label="Permalink to &quot;🛠️ 怎么在 VitePress 中开启？&quot;">​</a></h3><p>就像你提到的，在 VitePress 中开启它极其简单，只需要在你的项目配置文件（如 <code>.vitepress/config.mts</code> 或 <code>.vitepress/config.js</code>）中加上一行 <code>lazyLoading: true</code>：</p><p>TypeScript</p><div class="language-mts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// .vitepress/config.mts</span></span>
<span class="line"><span>export default {</span></span>
<span class="line"><span>  title: &quot;我的文档&quot;,</span></span>
<span class="line"><span>  themeConfig: {</span></span>
<span class="line"><span>    // ... 其他配置</span></span>
<span class="line"><span>  },</span></span>
<span class="line"><span>  markdown: {</span></span>
<span class="line highlighted"><span>    lazyLoading: true // 开启 Markdown 图片懒加载</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>开启后，VitePress 在把你的 Markdown 编译成网页时，会自动给所有的 <code>&lt;img&gt;</code> 标签加上 <code>loading=&quot;lazy&quot;</code> 这个标准的浏览器原生属性，不需要你手动去写复杂的 JavaScript 脚本。</p><p>你目前的文档里是有非常多的图片需要展示，还是在提前规划网站的性能优化呢？</p><h1 id="markdown里面都有些啥" tabindex="-1">markdown里面都有些啥 <a class="header-anchor" href="#markdown里面都有些啥" aria-label="Permalink to &quot;markdown里面都有些啥&quot;">​</a></h1><p>这是因为 VitePress 的配置文件有一个清晰的<strong>分层管理架构</strong>。</p><p>在 VitePress 中，<code>markdown</code> 是一个<strong>独立的配置大类（对象）</strong>，所有专门用来控制 Markdown 文件如何解析、编译、渲染的开关，都必须统一打包塞进 <code>markdown: { ... }</code> 的大括号内部。</p><p>如果把它拆开来看，它的逻辑是这样的：</p><p>TypeScript</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>export default {</span></span>
<span class="line"><span>  // 1. 这里放全局的基础配置</span></span>
<span class="line"><span>  title: &quot;我的文档&quot;,</span></span>
<span class="line"><span>  description: &quot;这是一个测试网站&quot;,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  // 2. 这里放和“网站主题、导航栏、侧边栏”相关的配置</span></span>
<span class="line"><span>  themeConfig: {</span></span>
<span class="line"><span>    nav: [ { text: &#39;首页&#39;, link: &#39;/&#39; } ],</span></span>
<span class="line"><span>    sidebar: [ ... ]</span></span>
<span class="line"><span>  },</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  // 3. 这里专门放和“Markdown 文本解析”相关的配置</span></span>
<span class="line"><span>  markdown: {</span></span>
<span class="line"><span>    lineNumbers: true,   // 比如：是否在代码块显示行号</span></span>
<span class="line"><span>    lazyLoading: true    // 比如：是否给 Markdown 里的图片开启懒加载</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="为什么不能直接写在外层" tabindex="-1">为什么不能直接写在外层？ <a class="header-anchor" href="#为什么不能直接写在外层" aria-label="Permalink to &quot;为什么不能直接写在外层？&quot;">​</a></h3><p>如果把 <code>lazyLoading: true</code> 直接写在最外层（和 <code>title</code> 平级），VitePress 的底层解析器就会“迷路”。</p><p>因为最外层是留给整个网站全局参数的，VitePress 根本不知道这个 <code>lazyLoading</code> 到底是要给网站的哪个功能用（是给系统里的某些插件用？还是给主题渲染用？）。</p><p>只有把它放进 <code>markdown: { ... }</code> 内部，VitePress 才会明白：“<strong>哦！原来这是针对 Markdown 编译器的指令。当你在把 <code>.md</code> 文件转换成 HTML 网页时，记得顺便把里面的图片都加上懒加载属性。</strong>”</p><p>这就好比归类整理物品：衣服放进衣柜，碗筷放进碗柜。<code>lazyLoading</code> 属于 Markdown 处理规则的一员，所以必须老老实实待在 <code>markdown</code> 的大括号格子里。</p>`,29)])])}const u=a(t,[["render",o]]);export{h as __pageData,u as default};
